V_{i}:=\left\{(u, v) \in U, \quad \nu_{i} \leq v<\nu_{i+1}\right\} . \tag{4}
\end{equation*}
\]

\[
\begin{equation*}
|\tilde{\mathrm{x}}(u, v)-\tilde{\mathrm{x}}(u, v+h)|=h\left|\tilde{\mathrm{x}}_{v}\left(u, v^{*}\right)\right|, \quad \tilde{\mathrm{x}}_{v}:=\frac{\partial \tilde{\mathrm{x}}}{\partial v} \tag{5}
\end{equation*}
\]

\[
\begin{align*}
h \rho_{i}(v) & <1, \quad v \in\left[\nu_{i} . \nu_{i+1}\right]  \tag{6}\\
\rho_{i}(v) & :=\max \left\{\sup _{u}\left|\tilde{\mathrm{x}}_{v}(u, v)\right|, \sup _{u}\left|\tilde{\mathrm{y}}_{v}(u, v)\right|\right\}
\end{align*}
\]

\[
\begin{equation*}
\mu_{i}:=\left\lceil\left(\nu_{i+1}-\nu_{i}\right) \sup _{v \in\left[\nu_{i} . . \nu_{i+1}\right]} \rho_{i}(v)\right\rceil \tag{7}
\end{equation*}
\]

\[
\begin{equation*}
\tilde{\mathbf{x}}_{v}=\tilde{\mathbf{x}}_{x} x_{v}+\tilde{\mathbf{x}}_{y} y_{v}+\tilde{\mathbf{x}}_{z} z_{v}=\frac{w_{x}}{z}\left(x_{v}-\frac{x}{z} z_{v}\right) \tag{8}
\end{equation*}
\]

\[
\begin{equation*}
\rho_{\alpha}:=\max \left\{\left|\tilde{\mathrm{x}}_{v}\left(u_{\alpha}, v_{\alpha}\right)\right|,\left|\tilde{\mathrm{y}}_{v}\left(u_{\alpha}, v_{\alpha}\right)\right|\right\} \tag{9}
\end{equation*}
\]

\[
\begin{equation*}
\mu_{i}:=\left(\nu_{i+1}-\nu_{i}\right) \max _{\alpha} \rho_{\alpha}, \quad \alpha \in V_{i} . \tag{10}
\end{equation*}
\]

\[
\begin{equation*}
\operatorname{base}_{i}+j, \quad \operatorname{base}_{i}:=\sum_{k=1}^{i-1} \mu_{k}, \quad j:=\frac{v-\nu_{i}}{\nu_{i+1}-\nu_{i}} \mu_{i}, \tag{11}
\end{equation*}
\]

